import { useEffect, useState } from "react";
import axios from "axios";

export default function Dashboard() {
  const [productos, setProductos] = useState([]);
  const [nuevoProducto, setNuevoProducto] = useState({
    nombre: "",
    precio: "",
    stock: "",
  });
  const [editando, setEditando] = useState(null);

  // 🔹 Obtener productos
  const obtenerProductos = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/productos");
      setProductos(res.data);
    } catch (error) {
      console.error("Error al obtener productos:", error);
    }
  };

  useEffect(() => {
    obtenerProductos();
  }, []);

  // 🔹 Manejar cambios del formulario
  const handleChange = (e) => {
    setNuevoProducto({ ...nuevoProducto, [e.target.name]: e.target.value });
  };

  // 🔹 Crear o actualizar producto
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editando) {
        await axios.put(
          `http://localhost:5000/api/productos/${editando.productoID}`,
          nuevoProducto
        );
      } else {
        await axios.post("http://localhost:5000/api/productos", nuevoProducto);
      }
      setNuevoProducto({ nombre: "", precio: "", stock: "" });
      setEditando(null);
      obtenerProductos();
    } catch (error) {
      console.error("Error al guardar producto:", error);
    }
  };

  // 🔹 Editar producto
const editarProducto = (producto) => {
  setNuevoProducto({
    nombre: producto.nombre || "",
    precio: producto.precio || "",
    stock: producto.stock || "",
  });
  setEditando(producto);
};


  // 🔹 Eliminar producto
  const eliminarProducto = async (productoID) => {
    if (window.confirm("¿Seguro que deseas eliminar este producto?")) {
      try {
        await axios.delete(`http://localhost:5000/api/productos/${productoID}`);
        obtenerProductos();
      } catch (error) {
        console.error("Error al eliminar producto:", error);
      }
    }
  };

  return (
    <div className="p-8 max-w-4xl mx-auto">
      <h1 className="text-3xl font-bold mb-6 text-center">
        🛍️ Gestión de Productos
      </h1>

      {/* Formulario para agregar/editar producto */}
      <form
        onSubmit={handleSubmit}
        className="bg-white shadow-md rounded-lg p-6 mb-8 border"
      >
        <h2 className="text-xl font-semibold mb-4">
          {editando ? "✏️ Editar Producto" : "➕ Agregar Producto"}
        </h2>

        <div className="grid grid-cols-3 gap-4 mb-4">
          <input
            type="text"
            name="nombre"
            value={nuevoProducto.nombre}
            onChange={handleChange}
            placeholder="Nombre"
            className="border p-2 rounded"
            required
          />
          <input
            type="number"
            name="precio"
            value={nuevoProducto.precio}
            onChange={handleChange}
            placeholder="Precio"
            className="border p-2 rounded"
            required
          />
          <input
            type="number"
            name="stock"
            value={nuevoProducto.stock}
            onChange={handleChange}
            placeholder="Stock"
            className="border p-2 rounded"
            required
          />
        </div>

        <button
          type="submit"
          className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700"
        >
          {editando ? "Actualizar" : "Agregar"}
        </button>

        {editando && (
          <button
            type="button"
            onClick={() => {
              setEditando(null);
              setNuevoProducto({ nombre: "", precio: "", stock: "" });
            }}
            className="ml-4 bg-gray-500 text-white px-4 py-2 rounded hover:bg-gray-600"
          >
            Cancelar
          </button>
        )}
      </form>

      {/* Tabla de productos */}
      <table className="w-full border border-gray-300 shadow-md bg-white">
        <thead>
          <tr className="bg-gray-100">
            <th className="border px-4 py-2">ID</th>
            <th className="border px-4 py-2">Nombre</th>
            <th className="border px-4 py-2">Precio</th>
            <th className="border px-4 py-2">Stock</th>
            <th className="border px-4 py-2">Acciones</th>
          </tr>
        </thead>
        <tbody>
          {productos.length === 0 ? (
            <tr>
              <td colSpan="5" className="text-center py-4">
                No hay productos registrados.
              </td>
            </tr>
          ) : (
            productos.map((p) => (
              <tr key={p.productoID}>
                <td className="border px-4 py-2">{p.productoID}</td>
                <td className="border px-4 py-2">{p.nombre}</td>
                <td className="border px-4 py-2">${p.precio}</td>
                <td className="border px-4 py-2">{p.stock}</td>
                <td className="border px-4 py-2 flex justify-center gap-2">
                  <button
                    onClick={() => editarProducto(p)}
                    className="bg-yellow-500 text-white px-3 py-1 rounded hover:bg-yellow-600"
                  >
                    Editar
                  </button>
                  <button
                    onClick={() => eliminarProducto(p.productoID)}
                    className="bg-red-600 text-white px-3 py-1 rounded hover:bg-red-700"
                  >
                    Eliminar
                  </button>
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
}
